    if not patents_info:
        return None
    m = re.search(r'pub\. number\s+([A-Z]{2}-[0-9]+[A-Z0-9-]*?)\b', patents_info)
    if m:
        return m.group(1)
    # other patterns
    m = re.search(r'publication number\s+([A-Z]{2}-[0-9]+[A-Z0-9-]*?)\b', patents_info)
    if m:
        return m.group(1)
    return None

uc_pubs = []
